import styled from '@emotion/styled'
import { VerticalCenterContainer } from '@kyokuya-demo/component/container'
import { SudokuBoard, SudokuGame } from '@kyokuya/react-game-sudoku'
import {
  SudokuActionType,
  SudokuContextProvider,
  SudokuContextType,
} from '@kyokuya/react-game-sudoku-core'
import Slider from '@mui/material/Slider'
import React from 'react'

const SUDOKU_SIZE_SQRT = 3
const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT

const SudokuGameDemoContainer = styled(VerticalCenterContainer)`
  margin: 2rem 0;
  background: #f3f3f3;

  @media screen and (max-width: 767px) {
    margin-left: -1rem;
    width: calc(100vw - 2px);
    .game-sudoku {
      width: 100%;
    }
  }
`

export const SudokuGameDemo: React.FC = () => (
  <SudokuGameDemoContainer>
    <SudokuGame storageKey="@post/game/sudoku/context0" />
  </SudokuGameDemoContainer>
)

export const SudokuBoard1: React.FC = () => {
  return (
    <VerticalCenterContainer>
      <SudokuContextProvider
        initialState={{
          activatedCell: { r: SUDOKU_SIZE >> 1, c: SUDOKU_SIZE >> 1 },
        }}
      >
        <SudokuContextType.Consumer>
          {({ state }) => <SudokuBoard attempt={state.solution} hintCell={null} />}
        </SudokuContextType.Consumer>
      </SudokuContextProvider>
    </VerticalCenterContainer>
  )
}

const SudokuBoard2Container = styled(VerticalCenterContainer)`
  margin: 2rem 0;
`
export const SudokuBoard2: React.FC = () => {
  return (
    <SudokuBoard2Container>
      <SudokuContextProvider
        initialState={{
          activatedCell: { r: SUDOKU_SIZE >> 1, c: SUDOKU_SIZE >> 1 },
        }}
      >
        <SudokuContextType.Consumer>
          {({ state, dispatch }) => (
            <React.Fragment>
              <Slider
                value={state.difficulty}
                step={1}
                min={0}
                max={100}
                valueLabelDisplay="on"
                aria-labelledby="sudoku-difficulty"
                onChange={(e, v) =>
                  dispatch({
                    type: SudokuActionType.RESET,
                    payload: { difficulty: v as number },
                  })
                }
                style={{ maxWidth: 400, margin: '8px 0' }}
              />
              <SudokuBoard attempt={state.attemptRef.current} hintCell={null} />
            </React.Fragment>
          )}
        </SudokuContextType.Consumer>
      </SudokuContextProvider>
    </SudokuBoard2Container>
  )
}
